update public.lessons l set enhancements = $ench${"industryStory":"Two testers were given the same feature. One started clicking immediately; the other spent twenty minutes on test analysis and a quick test plan first. The second tester found more issues, in less time, and could explain exactly what was and was not covered. The difference was following the STLC instead of improvising.","visualAid":{"type":"flow","title":"The Software Testing Life Cycle (STLC)","steps":[{"label":"Requirement Analysis"},{"label":"Test Planning"},{"label":"Test Case Design"},{"label":"Environment Setup"},{"label":"Test Execution"},{"label":"Test Closure"}],"caption":"A repeatable process that turns \"clicking around\" into professional testing."},"davidTip":"Even under pressure, do not skip analysis and design. As a QA lead, when someone tells me \"I tested it\", my next question is \"what did you cover, and what did you decide not to?\" The STLC is what lets you answer that with confidence instead of a shrug.","miniChallenge":"For a login feature, write a mini test plan: 3 things in scope, 2 things out of scope, and 5 test case titles you would design.","modelAnswer":"## Example — Login\n**In scope:** valid login, invalid password, locked account after N attempts.\n**Out of scope:** password-reset emails (separate feature), social login (not built yet).\n**Test case titles:**\n- Valid email and password logs in successfully\n- Wrong password shows a clear error\n- Empty fields are rejected\n- Account locks after 5 failed attempts\n- Email is case-insensitive","portfolioBuilder":"This mini test plan is the seed of a real portfolio artefact. Keep it — you will expand the test-planning skill in later modules and showcase a full plan at the end.","resourcePreview":{"name":"STLC Cheat Sheet","purpose":"The STLC phases with the key activities and outputs of each.","whenToUse":"Use it as a checklist when you start testing any new feature.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
